import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule } from '@angular/router';
import { FormControl, ReactiveFormsModule } from '@angular/forms';
import { combineLatest, map, startWith } from 'rxjs';
import { Quote } from '../../models/quote';
import { QuoteCalcService } from '../../services/quote-calc.service';
import { QuoteStoreService } from '../../services/quote-store.service';

@Component({
  selector: 'app-quote-list',
  standalone: true,
  imports: [CommonModule, RouterModule, ReactiveFormsModule],
  templateUrl: './quote-list.component.html',
  styleUrls: ['./quote-list.component.css']
})
export class QuoteListComponent implements OnInit {
  readonly searchControl = new FormControl('', { nonNullable: true });
  readonly filteredQuotes$ = combineLatest([
    this.store.quotes$,
    this.searchControl.valueChanges.pipe(startWith(''))
  ]).pipe(
    map(([quotes, term]) => {
      const query = term.trim().toLowerCase();
      if (!query) {
        return quotes;
      }

      return quotes.filter((quote) => {
        return (
          quote.numero.toLowerCase().includes(query) ||
          quote.client.nom.toLowerCase().includes(query)
        );
      });
    })
  );

  constructor(private store: QuoteStoreService, private calc: QuoteCalcService) {}

  async ngOnInit(): Promise<void> {
    await this.store.load();
  }

  totalTTC(quote: Quote): number {
    return this.calc.totals(quote).totalTTC;
  }

  async deleteQuote(quote: Quote): Promise<void> {
    const confirmed = confirm(`Supprimer le devis ${quote.numero} ?`);
    if (!confirmed) {
      return;
    }

    await this.store.delete(quote.id);
  }
}
<section class="panel card">
  <div class="panel-header">
    <div>
      <h1>Liste des devis</h1>
      <p>G&eacute;rez l&rsquo;historique des devis en un coup d&rsquo;&oelig;il.</p>
    </div>
    <div class="panel-actions">
      <input
        class="input"
        type="search"
        placeholder="Rechercher par num&eacute;ro ou client"
        [formControl]="searchControl"
      >
      <a class="btn primary" routerLink="/quotes/new">Nouveau</a>
    </div>
  </div>

  <div class="table">
    <div class="table-row table-head">
      <div>Num&eacute;ro</div>
      <div>Date</div>
      <div>Client</div>
      <div>Total TTC</div>
      <div>Actions</div>
    </div>
    <div class="table-row" *ngFor="let quote of filteredQuotes$ | async">
      <div class="mono">{{ quote.numero }}</div>
      <div>{{ quote.date | date:'dd/MM/yyyy' }}</div>
      <div>{{ quote.client.nom }}</div>
      <div class="amount">{{ totalTTC(quote) | number:'1.2-2' }} DT</div>
      <div class="actions">
        <a class="btn outline" [routerLink]="['/quotes', quote.id, 'preview']">Aper&ccedil;u</a>
        <a class="btn ghost" [routerLink]="['/quotes', quote.id, 'edit']">Modifier</a>
        <button class="btn danger" type="button" (click)="deleteQuote(quote)">Supprimer</button>
      </div>
    </div>
  </div>

  <div class="empty" *ngIf="(filteredQuotes$ | async)?.length === 0">
    Aucun devis trouv&eacute;.
  </div>
</section>
